                target_va_range@.contains(va) == false && old(self).get_address_space(
                    target_proc_ptr,
                ).dom().contains(va) ==> self.get_address_space(target_proc_ptr)[va] == old(
                    self,
                ).get_address_space(target_proc_ptr)[va],
    {
